return (
  <AuthShell
    title={mode === 'login' ? 'Masuk ke Workspace' : 'Buat Akun Baru'}
    description={
      mode === 'login'
        ? 'Gunakan email terdaftar atau Google untuk melanjutkan ke pemilihan workspace group.'
        : 'Daftarkan akun terlebih dahulu. Setelah login, Anda wajib membuat 1 workspace organisasi.'
    }
  >
    <div className="space-y-4">
      {/* Google Authentication Option - Compact and Premium */}
      <DsButton 
        variant="outline" 
        disabled={loading} 
        className="w-full justify-center gap-2.5 h-11 text-sm font-medium border-border/80 hover:border-foreground/20 hover:bg-muted/50 transition-all duration-200" 
        onClick={onGoogleLogin}
      >
        <svg aria-hidden="true" viewBox="0 0 24 24" className="h-4.5 w-4.5">
          <path fill="#EA4335" d="M12 10.2v3.9h5.4c-.2 1.2-1.4 3.6-5.4 3.6-3.2 0-5.8-2.7-5.8-6s2.6-6 5.8-6c1.8 0 3.1.8 3.8 1.5l2.6-2.5C16.8 3.2 14.6 2.3 12 2.3 6.8 2.3 2.6 6.6 2.6 12s4.2 9.7 9.4 9.7c5.4 0 9-3.8 9-9.2 0-.6-.1-1.1-.1-1.5H12z" />
          <path fill="#34A853" d="M3.6 7.8l3.2 2.4c.9-2 2.8-3.4 5.2-3.4 1.8 0 3.1.8 3.8 1.5l2.6-2.5C16.8 3.2 14.6 2.3 12 2.3c-3.7 0-6.9 2.1-8.4 5.5z" />
          <path fill="#4A90E2" d="M12 21.7c2.5 0 4.7-.8 6.3-2.3l-2.9-2.4c-.8.6-1.9 1-3.4 1-2.4 0-4.4-1.6-5.2-3.8l-3.3 2.5c1.5 3.5 4.8 5 8.5 5z" />
          <path fill="#FBBC05" d="M3.5 16.6l3.3-2.5c-.2-.6-.3-1.3-.3-2s.1-1.4.3-2l-3.2-2.4C2.9 9 2.6 10.4 2.6 12s.3 3 .9 4.6z" />
        </svg>
        Lanjut dengan Google
      </DsButton>

      {/* Minimalist Divider */}
      <div className="relative flex items-center justify-center py-2">
        <div className="absolute inset-0 flex items-center">
          <div className="w-full border-t border-border/60" />
        </div>
        <span className="relative bg-panel px-3 text-[11px] font-medium uppercase tracking-wider text-muted-foreground">atau gunakan email</span>
      </div>

      {/* Email/Form Section */}
      <div className="space-y-4">
        <div className="space-y-3">
          {mode === 'register' && (
            <DsInput 
              placeholder="Nama lengkap" 
              value={name} 
              onChange={(e) => setName(e.target.value)} 
              className="h-11 border-border/80"
              disabled={loading}
            />
          )}
