      <div className="space-y-3">
        <DsInput placeholder="Nama organisasi" value={organizationName} onChange={(e) => setOrganizationName(e.target.value)} />
        <DsInput placeholder="Kode organisasi (opsional)" value={organizationCode} onChange={(e) => setOrganizationCode(e.target.value)} />
