import { NextResponse } from 'next/server';
import { prisma } from '@/lib/prisma';

export async function GET(req: Request) {
  try {
    const { searchParams } = new URL(req.url);
    const code = searchParams.get('code');
    if (!code) {
      return NextResponse.json({ error: 'CODE_REQUIRED' }, { status: 400 });
    }

    const normalizedCode = code.toUpperCase().replace(/[^A-Z0-9-]/g, '-').slice(0, 24);
    if (!normalizedCode) {
      return NextResponse.json({ available: false });
    }

    const existing = await prisma.workspaceGroup.findUnique({
      where: { organizationCode: normalizedCode }
    });

    return NextResponse.json({ available: !existing });
  } catch (error) {
    console.error('Error checking organization code:', error);
    return NextResponse.json({ error: 'INTERNAL_SERVER_ERROR' }, { status: 500 });
  }
}

'use client';

import { useState, useEffect } from 'react';
import { useRouter } from 'next/navigation';
import { DsButton } from '@/shared/design-system/components/button';
import { DsInput } from '@/shared/design-system/components/input';
import { DsCard, DsCardContent } from '@/shared/design-system/components/card';
import { Check, X, Loader2 } from 'lucide-react';

export default function WorkspaceOnboardingPage() {
  const router = useRouter();
  const [organizationName, setOrganizationName] = useState('');
  const [organizationCode, setOrganizationCode] = useState('');
  const [isCodeManualEdited, setIsCodeManualEdited] = useState(false);
  const [workspaceName, setWorkspaceName] = useState('');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  // Uniqueness states
  const [checkingCode, setCheckingCode] = useState(false);
  const [codeAvailable, setCodeAvailable] = useState<boolean | null>(null);

  const generateSlug = (str: string) => {
    return str
      .toLowerCase()
      .replace(/[^a-z0-9\s-]/g, '')
      .trim()
      .replace(/\s+/g, '-')
      .replace(/-+/g, '-');
  };

  const handleNameChange = (val: string) => {
    setOrganizationName(val);
    if (!isCodeManualEdited) {
      setOrganizationCode(generateSlug(val));
    }
  };

  const handleCodeChange = (val: string) => {
    setOrganizationCode(val);
    setIsCodeManualEdited(val !== '');
  };

  // Debounced unique code checking
  useEffect(() => {
    const trimmed = organizationCode.trim();
    if (!trimmed) {
      setCodeAvailable(null);
      setCheckingCode(false);
      return;
    }

    setCheckingCode(true);
    const timer = setTimeout(async () => {
      try {
        const res = await fetch(`/api/workspaces/check-code?code=${encodeURIComponent(trimmed)}`);
        if (res.ok) {
          const data = await res.json();
          setCodeAvailable(data.available);
        } else {
          setCodeAvailable(null);
        }
      } catch {
        setCodeAvailable(null);
      } finally {
        setCheckingCode(false);
      }
    }, 450); // 450ms debounce time

    return () => clearTimeout(timer);
  }, [organizationCode]);

  const onCreate = async () => {
    if (codeAvailable === false) return;

    setLoading(true);
    setError(null);
    const res = await fetch('/api/workspaces/onboarding', {
      method: 'POST',
      headers: { 'content-type': 'application/json' },
      body: JSON.stringify({ organizationName, organizationCode, workspaceName })
    });
    const json = await res.json();
    setLoading(false);
    if (!res.ok) {
      setError(json.error ?? 'ONBOARDING_FAILED');
      return;
    }

    await fetch('/api/workspaces/select', {
      method: 'POST',
      headers: { 'content-type': 'application/json' },
      body: JSON.stringify({ workspaceGroupId: json.workspace.id })
    });

    router.push('/workspaces');
  };

  return (
    <main className="relative flex min-h-screen items-center justify-center bg-background px-5 py-10 sm:px-6">
      <div className="w-full max-w-md space-y-6">
        {/* Top Branding & Info */}
        <div className="text-center space-y-2">
          <p className="text-xs font-bold tracking-[0.25em] text-primary">VARGUARD EA</p>
          <h2 className="text-2xl font-semibold tracking-tight text-foreground">Setup Workspace</h2>
          <p className="text-xs text-muted-foreground max-w-sm mx-auto leading-relaxed">
            Create your first organization to activate your workspace group and start architecture analysis.
          </p>
        </div>

        {/* Setup Form Card */}
        <DsCard className="border border-border bg-panel shadow-sm overflow-hidden">
          <DsCardContent className="p-6 sm:p-8 space-y-4">
            <div className="space-y-3">
              {/* Organization Name */}
              <div className="space-y-1">
                <label className="text-[11px] font-semibold uppercase tracking-wider text-muted-foreground px-0.5">Organization Name</label>
                <DsInput 
                  placeholder="e.g. Acme Corporation" 
                  value={organizationName} 
                  onChange={(e) => handleNameChange(e.target.value)} 
                  className="h-11 border-border"
                  disabled={loading}
                />
              </div>

              {/* Organization Code (Validated) */}
              <div className="space-y-1">
                <div className="flex justify-between items-center px-0.5">
                  <label className="text-[11px] font-semibold uppercase tracking-wider text-muted-foreground">Organization Code</label>
                  {checkingCode && (
                    <span className="text-[10px] text-muted-foreground animate-pulse">Checking availability...</span>
                  )}
                </div>
                <div className="relative">
                  <DsInput 
                    placeholder="e.g. acme" 
                    value={organizationCode} 
                    onChange={(e) => handleCodeChange(e.target.value)} 
                    className="h-11 border-border pr-10"
                    disabled={loading}
                  />
                  <div className="absolute right-3.5 top-1/2 -translate-y-1/2 flex items-center pointer-events-none">
                    {checkingCode ? (
                      <Loader2 className="h-4 w-4 text-muted-foreground animate-spin" />
                    ) : codeAvailable === true ? (
                      <Check className="h-4 w-4 text-success" strokeWidth={3} />
                    ) : codeAvailable === false ? (
                      <X className="h-4 w-4 text-destructive" strokeWidth={3} />
                    ) : null}
                  </div>
                </div>
                {codeAvailable === false && (
                  <p className="text-[11px] font-medium text-destructive px-0.5 pt-0.5">
                    This organization code is already taken. Please choose another.
                  </p>
                )}
              </div>

              {/* Default Workspace */}
              <div className="space-y-1">
                <label className="text-[11px] font-semibold uppercase tracking-wider text-muted-foreground px-0.5">Default Workspace</label>
                <DsInput 
                  placeholder="e.g. Main Repository" 
                  value={workspaceName} 
                  onChange={(e) => setWorkspaceName(e.target.value)} 
                  className="h-11 border-border"
                  disabled={loading}
                />
              </div>
            </div>

            {error && (
              <p className="text-xs font-medium text-destructive bg-destructive-soft border border-destructive-soft-border rounded-control p-2.5">
                {error === 'ONBOARDING_FAILED' 
                  ? 'Failed to setup workspace. Please check your inputs.' 
                  : error}
              </p>
            )}

            {/* Action Button */}
            <DsButton 
              onClick={onCreate} 
              disabled={
                loading || 
                !organizationName || 
                !workspaceName || 
                !organizationCode.trim() || 
                codeAvailable === false || 
                checkingCode
              }
              className="w-full h-11 justify-center font-semibold text-sm shadow-sm transition-all duration-200 mt-2"
            >
              {loading ? 'Setting up...' : 'Create Workspace'}
            </DsButton>
          </DsCardContent>
        </DsCard>
      </div>
    </main>
  );
}

