export async function createInitialWorkspaceGroup(params: {
  appUserId: string;
  organizationName: string;
  organizationCode: string;
  workspaceName: string;
  architectureFramework?: string;
}) {
  return prisma.$transaction(async (tx) => {
    const existing = await tx.workspaceMembership.findFirst({ where: { appUserId: params.appUserId } });
    if (existing) throw new Error('WORKSPACE_ALREADY_EXISTS');

    const group = await tx.workspaceGroup.create({
      data: {
        organizationName: params.organizationName,
        organizationCode: params.organizationCode,
        createdByUserId: params.appUserId
      }
    });

    await tx.workspaceMembership.create({
      data: {
        appUserId: params.appUserId,
        workspaceGroupId: group.id,
        role: 'ORG_ADMIN'
      }
    });

    const workspace = await tx.workspace.create({
      data: {
        workspaceGroupId: group.id,
        name: params.workspaceName,
        description: `Default workspace for ${params.organizationName}`,
        architectureFramework: params.architectureFramework ?? 'generic'
      }
    });

    return { group, workspace };
  });
}

