import { PrismaClient } from '@prisma/client';

const prisma = new PrismaClient();

const frameworks = [
  {
    code: 'archimate',
    name: 'ArchiMate 3.1 Template',
    description: 'Perfect for TOGAF-aligned enterprise architecture modeling. Provides standard ArchiMate layers (Strategy, Business, Application, Technology).',
  },
  {
    code: 'bpmn',
    name: 'BPMN 2.0 Process Map',
    description: 'Optimized for business process modeling, governance, and flowcharts. Standard process and collaboration diagrams.',
  },
  {
    code: 'togaf',
    name: 'TOGAF 10 ADM Catalog',
    description: 'Pre-configured architecture repository structured according to the TOGAF Architecture Development Method phases.',
  },
  {
    code: 'generic',
    name: 'Generic EA Catalog',
    description: 'Simple, unopinionated structure for custom model catalogs and architectural mapping.',
  }
];

async function main() {
  console.log('Seeding architecture frameworks...');
  for (const fw of frameworks) {
    const upserted = await prisma.architectureFramework.upsert({
      where: { code: fw.code },
      update: {
        name: fw.name,
        description: fw.description,
      },
      create: {
        code: fw.code,
        name: fw.name,
        description: fw.description,
      },
    });
    console.log(`Seeded framework: ${upserted.code} (${upserted.name})`);
  }
  console.log('Seeding completed successfully.');
}

main()
  .catch((e) => {
    console.error('Error during seeding:', e);
    process.exit(1);
  })
  .finally(async () => {
    await prisma.$disconnect();
  });

