export default function StudioHeader() {
  const router = useRouter();
  const searchRef = useRef<HTMLInputElement>(null);
  const enterpriseMenuRef = useRef<HTMLDivElement>(null);
  const searchContainerRef = useRef<HTMLDivElement>(null);
  const [enterpriseMenuOpen, setEnterpriseMenuOpen] = useState(false);
  const [searchQuery, setSearchQuery] = useState('');
  const [searchOpen, setSearchOpen] = useState(false);

  const [workspaces, setWorkspaces] = useState<any[]>([]);
  const [selectedWorkspace, setSelectedWorkspace] = useState<string>('');

  useEffect(() => {
    fetch('/api/workspaces/mine')
      .then((r) => r.json())
      .then(async (data) => {
        const items = data.items ?? [];
        setWorkspaces(items);

        // Get ea_workspace_group from document.cookie
        const match = document.cookie.match(/ea_workspace_group=([^;]+)/);
        const cookieGroupId = match ? match[1] : null;

        if (items.length > 0) {
          // By default select cookieGroupId if valid, otherwise the first workspace (index 1 / item 0)
          const defaultId = items.some((item: any) => item.id === cookieGroupId)
            ? cookieGroupId
            : items[0].id;

          setSelectedWorkspace(defaultId);

          // If no cookie was set or it was different, select it
          if (cookieGroupId !== defaultId) {
            await fetch('/api/workspaces/select', {
              method: 'POST',
              headers: { 'content-type': 'application/json' },
              body: JSON.stringify({ workspaceGroupId: defaultId })
            });
          }
        }
      })
      .catch((e) => console.error('Failed to load workspaces in header', e));
  }, []);

  const handleWorkspaceChange = async (id: string) => {
    setSelectedWorkspace(id);
    const res = await fetch('/api/workspaces/select', {
      method: 'POST',
      headers: { 'content-type': 'application/json' },
      body: JSON.stringify({ workspaceGroupId: id })
    });
    if (res.ok) {
      window.location.href = `/enterprise/overview?group=${id}`;
    }
  };

  const filteredSuggestions = useMemo(() => {
    const q = searchQuery.trim().toLowerCase();
    if (!q) return SEARCH_SUGGESTIONS;
    return SEARCH_SUGGESTIONS.filter((item) =>
      item.title.toLowerCase().includes(q) ||
      item.description.toLowerCase().includes(q) ||
      item.category.toLowerCase().includes(q)
    );
  }, [searchQuery]);

