import { NextResponse } from 'next/server';
import type { NextRequest } from 'next/server';
import { auth } from '@/auth';

const protectedPrefixes = ['/workspaces', '/enterprise', '/api/organizations', '/api/artifacts', '/api/dashboard', '/api/workspaces', '/onboarding'];
const onboardingPath = '/onboarding/workspace';

function baseMiddleware(req: NextRequest) {
  const { pathname } = req.nextUrl;

  const isProtected = protectedPrefixes.some((prefix) => pathname.startsWith(prefix)) || pathname === '/workspace';
  if (!isProtected) return NextResponse.next();

  const authEmail = (req as NextRequest & { auth?: { user?: { email?: string | null } } }).auth?.user?.email ?? undefined;
  const email = req.cookies.get('ea_user_email')?.value ?? authEmail ?? undefined;
  if (!email) {
    if (pathname.startsWith('/api/')) {
      return NextResponse.json({ error: 'UNAUTHENTICATED' }, { status: 401 });
    }
    const url = req.nextUrl.clone();
    url.pathname = '/login';
    url.searchParams.set('next', pathname);
    return NextResponse.redirect(url);
  }

  const hasWorkspace = req.cookies.get('ea_has_workspace')?.value === '1';

  // Explicitly block and redirect /workspaces or /workspace routes (disabled)
  if (pathname === '/workspace' || pathname.startsWith('/workspaces')) {
    const url = req.nextUrl.clone();
    url.pathname = hasWorkspace ? '/enterprise/overview' : '/onboarding/workspace';
    return NextResponse.redirect(url);
  }

  const isOnboardingPath = pathname.startsWith(onboardingPath) || pathname.startsWith('/api/workspaces/onboarding');
  const requiresWorkspaceContext = pathname.startsWith('/enterprise')
    || pathname.startsWith('/api/organizations')
    || pathname.startsWith('/api/artifacts')
    || pathname.startsWith('/api/dashboard');
  if (!hasWorkspace && !isOnboardingPath) {
    if (requiresWorkspaceContext) {
      if (pathname.startsWith('/api/')) {
        return NextResponse.json({ error: 'WORKSPACE_SELECTION_REQUIRED', next: '/onboarding/workspace' }, { status: 428 });
      }
      const url = req.nextUrl.clone();
      url.pathname = '/onboarding/workspace';
      return NextResponse.redirect(url);
    }
  }

  const activeGroup = req.cookies.get('ea_workspace_group')?.value ?? undefined;
  if (hasWorkspace && !activeGroup && pathname.startsWith('/api/')) {
    return NextResponse.json({ error: 'WORKSPACE_GROUP_REQUIRED', next: '/enterprise/overview' }, { status: 428 });
  }

  const requestHeaders = new Headers(req.headers);
  requestHeaders.set('x-user-email', email);
  if (activeGroup) requestHeaders.set('x-workspace-group', activeGroup);

  const res = NextResponse.next({
    request: {
      headers: requestHeaders
    }
  });
  if (authEmail && req.cookies.get('ea_user_email')?.value !== authEmail) {
    res.cookies.set('ea_user_email', authEmail, {
      path: '/',
      httpOnly: false,
      sameSite: 'lax',
      maxAge: 60 * 60 * 8
    });
  }
  return res;
}

export default auth((req) => baseMiddleware(req as NextRequest));

export const config = {
  matcher: ['/workspace', '/workspaces/:path*', '/enterprise/:path*', '/api/organizations/:path*', '/api/artifacts/:path*', '/api/dashboard/:path*', '/api/workspaces/:path*', '/onboarding/:path*']
};

