import { DsButton } from '@/shared/design-system/components/button';
import { useCanvasModeStore } from '@/src/stores/canvas-mode-store';
import type { ToolbarItem } from './toolbar-types';

export default function ToolbarButton({ item }: { item: ToolbarItem }) {
  const Icon = item.icon;
  const [tooltip, setTooltip] = useState<{ x: number; y: number } | null>(null);
  const { mode, setMode } = useCanvasModeStore();
  const cycleMode = () => {
    const order = ['arrow', 'lasso', 'freehand'];
    const idx = order.indexOf(mode);
    setMode(order[(idx + 1) % order.length] as any);
  };
  return (
        <DsButton variant="ghost"
        onClick={item.onClick}
        disabled={item.disabled}
        className={[
          'h-7 w-7 rounded-sm px-0 text-foreground/90 hover:bg-muted',
          item.active ? 'bg-muted text-foreground ring-1 ring-border' : '',
        ].join(' ')}
        aria-label={item.label}
        onMouseEnter={(event) => {
          const rect = (event.currentTarget as HTMLButtonElement).getBoundingClientRect();
          const rawX = rect.left + rect.width / 2;
          const clampedX = Math.min(Math.max(rawX, 8), window.innerWidth - 8);
          setTooltip({ x: clampedX, y: rect.top - 8 });
        }}
        onMouseLeave={() => setTooltip(null)}
      >
        <Icon className="h-3.5 w-3.5" />
        {item.kind === 'dropdown' ? <ChevronDown className="absolute -bottom-0.5 -right-0.5 h-2.5 w-2.5 text-muted-foreground" /> : null}
      </DsButton>
      {tooltip
        ? createPortal(
            <div
              className="pointer-events-none fixed z-[120] -translate-x-1/2 -translate-y-full whitespace-nowrap rounded-sm bg-sidebar px-2 py-1 text-[10px] text-foreground shadow-card"
              style={{ left: tooltip.x, top: tooltip.y }}
            >
              <span className="font-medium">{item.label}</span>
              {item.description ? <span className="ml-1 text-muted-foreground">- {item.description}</span> : null}
            </div>,
            document.body
          )
        : null}
    </div>
  );
}

