'use client';

import { useEffect, useState } from 'react';

/**
 * StudioLoader – overlay loading yang mengkoordinasikan semua kondisi
 * sebelum studio ditampilkan:
 *  1. symbolsHydrated   – zustand store selesai baca localStorage
 *  2. editorReady       – BpmnEditor onInit dipanggil
 *  3. minDuration       – minimal 600ms agar tidak flicker
 */
export default function StudioLoader({
  symbolsHydrated,
  editorReady,
}: {
  symbolsHydrated: boolean;
  editorReady: boolean;
}) {
  const [minPassed, setMinPassed] = useState(false);
  const [hiding, setHiding] = useState(false);
  const [gone, setGone] = useState(false);

  // Minimal duration agar tidak terlalu cepat flicker
  useEffect(() => {
    const t = setTimeout(() => setMinPassed(true), 600);
    return () => clearTimeout(t);
  }, []);

  const allReady = symbolsHydrated && editorReady && minPassed;

  useEffect(() => {
    if (!allReady) return;
    // Mulai fade-out
    setHiding(true);
    const t = setTimeout(() => setGone(true), 500);
    return () => clearTimeout(t);
  }, [allReady]);

  if (gone) return null;

  return (
    <div
      aria-hidden
      style={{
        position: 'fixed',
        inset: 0,
        zIndex: 9999,
        display: 'flex',
        flexDirection: 'column',
        alignItems: 'center',
        justifyContent: 'center',
        backgroundColor: 'hsl(var(--background))',
        gap: '20px',
        transition: 'opacity 500ms ease, transform 500ms ease',
        opacity: hiding ? 0 : 1,
        transform: hiding ? 'scale(1.015)' : 'scale(1)',
        pointerEvents: hiding ? 'none' : 'all',
      }}
    >
      {/* Logo mark */}
      <div
        style={{
          display: 'flex',
          flexDirection: 'column',
          alignItems: 'center',
          gap: '16px',
        }}
      >
        {/* Animated icon */}
        <svg
          width="48"
          height="48"
          viewBox="0 0 48 48"
          fill="none"
          style={{ animation: 'studio-loader-pulse 1.6s ease-in-out infinite' }}
        >
          <defs>
            <linearGradient id="sl-grad" x1="0" y1="0" x2="48" y2="48" gradientUnits="userSpaceOnUse">
              <stop offset="0%" stopColor="hsl(195 92% 42%)" />
              <stop offset="100%" stopColor="hsl(208 100% 38%)" />
            </linearGradient>
          </defs>
          {/* Hexagon-like BPMN flow shape */}
          <rect x="4" y="4" width="40" height="40" rx="10" fill="url(#sl-grad)" opacity="0.12" />
          <rect x="4" y="4" width="40" height="40" rx="10" stroke="url(#sl-grad)" strokeWidth="1.5" fill="none" />
          {/* Flow dots */}
          <circle cx="14" cy="24" r="4" fill="url(#sl-grad)" />
          <line x1="18" y1="24" x2="22" y2="24" stroke="hsl(195 92% 42%)" strokeWidth="1.5" strokeDasharray="3 2" />
          <rect x="22" y="19" width="10" height="10" rx="2" fill="none" stroke="url(#sl-grad)" strokeWidth="1.5" />
          <line x1="32" y1="24" x2="36" y2="24" stroke="hsl(195 92% 42%)" strokeWidth="1.5" strokeDasharray="3 2" />
          <polygon points="36,24 40,20 40,28" fill="url(#sl-grad)" opacity="0.6" />
        </svg>

        {/* Brand name */}
        <div style={{ textAlign: 'center' }}>
          <p
            style={{
              fontSize: '13px',
              fontWeight: 600,
              letterSpacing: '0.14em',
              textTransform: 'uppercase',
              color: 'hsl(var(--foreground))',
              opacity: 0.9,
              margin: 0,
            }}
          >
            Varguard
          </p>
          <p
            style={{
              fontSize: '11px',
              color: 'hsl(var(--muted-foreground))',
              letterSpacing: '0.06em',
              margin: '2px 0 0',
            }}
          >
            BPMN Studio
          </p>
        </div>
      </div>

      {/* Progress dots */}
      <div style={{ display: 'flex', gap: '6px', alignItems: 'center' }}>
        {[0, 1, 2].map((i) => (
          <div
            key={i}
            style={{
              width: '5px',
              height: '5px',
              borderRadius: '50%',
              backgroundColor: 'hsl(var(--primary))',
              opacity: 0.4,
              animation: `studio-loader-dot 1.2s ease-in-out ${i * 0.2}s infinite`,
            }}
          />
        ))}
      </div>

      {/* Status text */}
      <p
        style={{
          fontSize: '10px',
          color: 'hsl(var(--muted-foreground))',
          letterSpacing: '0.04em',
          margin: 0,
          opacity: 0.7,
        }}
      >
        {!symbolsHydrated
          ? 'Memuat konfigurasi...'
          : !editorReady
            ? 'Menyiapkan canvas...'
            : 'Siap...'}
      </p>

      <style>{`
        @keyframes studio-loader-pulse {
          0%, 100% { transform: scale(1); opacity: 1; }
          50% { transform: scale(0.94); opacity: 0.75; }
        }
        @keyframes studio-loader-dot {
          0%, 80%, 100% { transform: translateY(0); opacity: 0.4; }
          40% { transform: translateY(-5px); opacity: 1; }
        }
      `}</style>
    </div>
  );
}

