'use client';

import { useCallback, useEffect, useRef, useState } from 'react';

type Direction = 'right' | 'left';

/**
 * useResizable – hook untuk membuat panel yang bisa di-resize dengan drag handle.
 *
 * @param storageKey  – kunci localStorage untuk menyimpan lebar
 * @param defaultWidth – lebar default jika belum ada di localStorage
 * @param min – lebar minimum (px)
 * @param max – lebar maksimum (px)
 * @param direction – 'right' jika drag ke kanan menambah lebar (left panel),
 *                    'left' jika drag ke kiri menambah lebar (right panel)
 */
export function useResizable({
  storageKey,
  defaultWidth,
  min,
  max,
  direction = 'right',
}: {
  storageKey: string;
  defaultWidth: number;
  min: number;
  max: number;
  direction?: Direction;
}) {
  const [width, setWidth] = useState<number>(() => {
    if (typeof window !== 'undefined') {
      const stored = localStorage.getItem(storageKey);
      if (stored) {
        const parsed = parseInt(stored, 10);
        if (!isNaN(parsed)) return Math.max(min, Math.min(max, parsed));
      }
    }
    return defaultWidth;
  });

  const [resizing, setResizing] = useState(false);
  const startXRef = useRef(0);
  const startWidthRef = useRef(width);

  // Persist ke localStorage setiap kali width berubah (debounced)
  const persistTimer = useRef<ReturnType<typeof setTimeout> | null>(null);
  useEffect(() => {
    if (persistTimer.current) clearTimeout(persistTimer.current);
    persistTimer.current = setTimeout(() => {
      localStorage.setItem(storageKey, String(width));
    }, 200);
    return () => {
      if (persistTimer.current) clearTimeout(persistTimer.current);
    };
  }, [width, storageKey]);

  const onMouseDown = useCallback(
    (e: React.MouseEvent) => {
      e.preventDefault();
      startXRef.current = e.clientX;
      startWidthRef.current = width;
      setResizing(true);
    },
    [width]
  );

  useEffect(() => {
    if (!resizing) return;

    const onMove = (e: MouseEvent) => {
      const delta = direction === 'right'
        ? e.clientX - startXRef.current
        : startXRef.current - e.clientX;
      const next = Math.max(min, Math.min(max, startWidthRef.current + delta));
      setWidth(next);
    };

    const onUp = () => setResizing(false);

    window.addEventListener('mousemove', onMove);
    window.addEventListener('mouseup', onUp);
    return () => {
      window.removeEventListener('mousemove', onMove);
      window.removeEventListener('mouseup', onUp);
    };
  }, [resizing, min, max, direction]);

  return { width, setWidth, resizing, onMouseDown };
}

