const BpmnEditor = dynamic(() => import('../components/BpmnEditor'), { ssr: false });
const TOOLBAR_HEIGHT = 40;
const FOOTER_HEIGHT = 28;
const SIDEBAR_WIDTH_EXPANDED = 288;
const SIDEBAR_WIDTH_COLLAPSED = 0;
const SYMBOLS_PANEL_WIDTH = 320;
const SYMBOLS_PANEL_COLLAPSED_WIDTH = 40;

// Use global store for symbols panel state
const { isSymbolsPanelOpen, _hasHydrated: symbolsHydrated } = useBpmnSymbolStore();
// Sebelum hydrated, anggap panel belum ada (width 0) agar layout tidak loncat
