{/* Area kerja: left repo sidebar + symbols panel + canvas + right detail sidebar */}
<div
  className="fixed flex overflow-hidden"
  style={{
    top: `${STUDIO_HEADER_HEIGHT + TOOLBAR_HEIGHT}px`,
    left: `${sidebarWidth}px`,
    right: 0,
    bottom: `${FOOTER_HEIGHT}px`,
  }}
>
  {/* Symbols panel – lebar diatur oleh useResizable di dalam komponen */}
  {symbolsHydrated ? (
    <BpmnSymbolsPanel
      onInsertSymbol={(symbol) => editorRef.current?.insertBpmnSymbol(symbol.key)}
      onActivateFlow={(symbol) => {
        if (!symbol.flowType) return;
        editorRef.current?.activateFlowConnection(symbol.flowType);
        setConnectionModeActive(true);
      }}
