'use client';

import { create } from 'zustand';

export type QuickConnectSide = 'top' | 'bottom' | 'left' | 'right';

type QuickConnectState = {
  /** ID node sumber yang sedang dalam mode quick-connect */
  sourceNodeId: string | null;
  /** Sisi dari node sumber yang diklik */
  sourceSide: QuickConnectSide | null;
  /** Aktifkan mode pilih target */
  startConnect: (nodeId: string, side: QuickConnectSide) => void;
  /** Batalkan mode */
  cancel: () => void;
};

export const useQuickConnectStore = create<QuickConnectState>((set) => ({
  sourceNodeId: null,
  sourceSide: null,
  startConnect: (nodeId, side) => set({ sourceNodeId: nodeId, sourceSide: side }),
  cancel: () => set({ sourceNodeId: null, sourceSide: null }),
}));

'use client';

import { useCallback } from 'react';
import { useQuickConnectStore, type QuickConnectSide } from '@/src/stores/canvas/quick-connect-store';

const SIDES: { side: QuickConnectSide; label: string; style: React.CSSProperties }[] = [
  {
    side: 'top',
    label: 'Tambah koneksi ke atas',
    style: {
      top: -14,
      left: '50%',
      transform: 'translateX(-50%)',
    },
  },
  {
    side: 'bottom',
    label: 'Tambah koneksi ke bawah',
    style: {
      bottom: -14,
      left: '50%',
      transform: 'translateX(-50%)',
    },
  },
  {
    side: 'left',
    label: 'Tambah koneksi ke kiri',
    style: {
      left: -14,
      top: '50%',
      transform: 'translateY(-50%)',
    },
  },
  {
    side: 'right',
    label: 'Tambah koneksi ke kanan',
    style: {
      right: -14,
      top: '50%',
      transform: 'translateY(-50%)',
    },
  },
];

/**
 * Overlay 4 tombol (+) yang muncul pada sisi node saat dipilih.
 * Klik salah satu → aktifkan mode quick-connect.
 */
export default function BpmnQuickConnectButtons({ nodeId }: { nodeId: string }) {
  const { sourceNodeId, startConnect } = useQuickConnectStore();

  // Jangan tampilkan jika node ini sendiri yang sedang jadi sumber
  const isSelf = sourceNodeId === nodeId;

  const handleClick = useCallback(
    (e: React.MouseEvent, side: QuickConnectSide) => {
      e.stopPropagation();
      e.preventDefault();
      startConnect(nodeId, side);
    },
    [nodeId, startConnect]
  );

  if (isSelf) return null;

  return (
    <>
      {SIDES.map(({ side, label, style }) => (
        <button
          key={side}
          type="button"
          aria-label={label}
          title={label}
          onMouseDown={(e) => e.stopPropagation()}
          onClick={(e) => handleClick(e, side)}
          className="nodrag nopan absolute z-20 flex h-[18px] w-[18px] items-center justify-center rounded-full border border-primary bg-card text-primary shadow-sm transition-all duration-150 hover:scale-110 hover:bg-primary hover:text-primary-foreground"
          style={style}
        >
          <svg
            width="10"
            height="10"
            viewBox="0 0 10 10"
            fill="none"
            stroke="currentColor"
            strokeWidth="1.8"
            strokeLinecap="round"
          >
            <line x1="5" y1="1" x2="5" y2="9" />
            <line x1="1" y1="5" x2="9" y2="5" />
          </svg>
        </button>
      ))}
    </>
  );
}

