'use client';

import type { ReactNode } from 'react';
import { NodeResizeControl, NodeResizer, type ResizeDragEvent, type ResizeParams } from '@xyflow/react';
import BpmnQuickConnectButtons from './BpmnQuickConnectButtons';
import { useQuickConnectStore } from '@/src/stores/canvas/quick-connect-store';

type Props = {
  nodeId: string;
  selected: boolean;
  minWidth: number;
  minHeight: number;
  maxWidth?: number;
  maxHeight?: number;
  keepAspectRatio?: boolean;
  onResize?: (event: ResizeDragEvent, params: ResizeParams) => void;
  onResizeEnd?: (event: ResizeDragEvent, params: ResizeParams) => void;
  children: ReactNode;
};

export default function BpmnResizableNode({
  nodeId,
  selected,
  minWidth,
  minHeight,
  maxWidth,
  maxHeight,
  keepAspectRatio = false,
  onResize,
  onResizeEnd,
  children,
}: Props) {
  const handleStyle = {
    width: 8,
    height: 8,
    borderRadius: 2,
    border: '1px solid hsl(var(--border))',
    background: 'hsl(var(--card))',
  };

  const { sourceNodeId } = useQuickConnectStore();
  const isPickTarget = !!sourceNodeId && sourceNodeId !== nodeId;

  return (
    <>
      <NodeResizer
        isVisible={selected}
        minWidth={minWidth}
        minHeight={minHeight}
        maxWidth={maxWidth}
        maxHeight={maxHeight}
        keepAspectRatio={keepAspectRatio}
        handleStyle={handleStyle}
        lineStyle={{ borderWidth: 1, borderColor: 'hsl(var(--border))' }}
        onResize={onResize}
        onResizeEnd={onResizeEnd}
      />
      <NodeResizeControl
        position="bottom-right"
        minWidth={minWidth}
        minHeight={minHeight}
        maxWidth={maxWidth}
        maxHeight={maxHeight}
        keepAspectRatio={keepAspectRatio}
        className={selected ? 'h-2 w-2 border border-border bg-card' : 'hidden'}
      />

      {children}

      {/* Quick-connect (+) buttons muncul saat node dipilih dan tidak sedang pick-target */}
      {selected && !isPickTarget ? <BpmnQuickConnectButtons nodeId={nodeId} /> : null}

      {/* Overlay indikator target saat mode quick-connect aktif */}
      {isPickTarget ? (
        <div
          className="nodrag nopan pointer-events-none absolute inset-0 z-30 rounded-[inherit] ring-2 ring-primary/60 ring-offset-1 transition-all"
          style={{ background: 'hsl(var(--primary) / 0.06)' }}
        />
      ) : null}
    </>
  );
}

