  onResize?: (event: ResizeDragEvent, params: ResizeParams) => void;
  onResizeEnd?: (event: ResizeDragEvent, params: ResizeParams) => void;
  children: ReactNode;
};

export default function BpmnResizableNode({
  selected,
  minWidth,
  minHeight,
  maxWidth,
  maxHeight,
  keepAspectRatio = false,
  onResize,
  onResizeEnd,
  children,
}: Props) {
  const handleStyle = {
    width: 8,
    height: 8,
    borderRadius: 2,
    border: '1px solid hsl(var(--border))',
    background: 'hsl(var(--card))',
  };

  return (
    <>
      <NodeResizer
        isVisible={selected}
        minWidth={minWidth}
        minHeight={minHeight}
        maxWidth={maxWidth}
        maxHeight={maxHeight}
        keepAspectRatio={keepAspectRatio}
        handleStyle={handleStyle}
        lineStyle={{ borderWidth: 1, borderColor: 'hsl(var(--border))' }}
        onResize={onResize}
        onResizeEnd={onResizeEnd}
      />
      <NodeResizeControl
        position="bottom-right"
        minWidth={minWidth}
        minHeight={minHeight}
        maxWidth={maxWidth}
        maxHeight={maxHeight}
        keepAspectRatio={keepAspectRatio}
        className={selected ? 'h-2 w-2 border border-border bg-card' : 'hidden'}
      />
      {children}
    </>
  );
}

