 * Saat mode quick-connect aktif, klik node target:
 * - Jika klik node yang sama dengan sumber → batalkan
 * - Jika klik node lain → buat edge dari sumber ke target
 *   lalu batalkan mode
 */
const handleNodeClick = useCallback(
  (_event: MouseEvent, targetNode: Node) => {
    if (!sourceNodeId) return;
    if (targetNode.id === sourceNodeId) {
      cancelQuickConnect();
      return;
    }

    // Tentukan posisi node baru berdasarkan sisi yang diklik
    const sourceNode = nodes.find((n) => n.id === sourceNodeId);
    if (!sourceNode) { cancelQuickConnect(); return; }

    const OFFSET = 200;
    const srcW = (sourceNode.style?.width as number) ?? 160;
    const srcH = (sourceNode.style?.height as number) ?? 72;
    const sx = sourceNode.position.x;
    const sy = sourceNode.position.y;

    const offsetMap: Record<string, XYPosition> = {
      right:  { x: sx + srcW + OFFSET, y: sy },
      left:   { x: sx - srcW - OFFSET, y: sy },
      bottom: { x: sx, y: sy + srcH + OFFSET },
      top:    { x: sx, y: sy - srcH - OFFSET },
    };
    const newPos = snapPosition(offsetMap[sourceSide ?? 'right'] ?? { x: sx + OFFSET, y: sy });

    // Buat node baru bertipe Task (default)
    const taskSymbol = BPMN_SYMBOLS_BY_KEY.get('task');
    const newNode: Node = taskSymbol
      ? (createBpmnNode(taskSymbol, newPos) as Node)
      : {
          id: `task-qc-${Date.now()}`,
          type: 'bpmnTask',
          position: newPos,
          data: { label: 'Task', bpmnType: 'bpmn:Task' },
          style: { width: 160, height: 72 },
        };

    // Buat edge dari sumber ke target yang diklik
    const newEdge: Edge = {
      id: `edge-qc-${Date.now()}`,
      source: sourceNodeId,
      target: targetNode.id,
      type: 'bpmnSequenceFlow',
      markerEnd: { type: MarkerType.ArrowClosed },
    };

    updateNodes((prev) => [...prev, newNode]);
    updateEdges((prev) => [...prev, newEdge]);
    cancelQuickConnect();
  },
  [sourceNodeId, sourceSide, nodes, cancelQuickConnect, snapPosition, updateNodes, updateEdges, createFlowEdge]
);

